    id, user_id, activity_date, poem_views, search_count, excerpt_count, favorite_count, created_at, updated_at
) VALUES (
    #{id}, #{userId}, #{activityDate}, #{poemViews}, #{searchCount}, #{excerptCount}, #{favoriteCount}, #{createdAt}, #{updatedAt}
